        "min": 1,
        "max": "1"
      },
      {
        "path": "Patient.birthDate",
        "min": 1,
        "max": "1"
      }
    ]
  }
}
```

### 2. **MedicationRequest Profile**
- **Purpose**: Define the core attributes of a medication request.
- **Constraints**:
  - Required fields (e.g., `medicationCodeableConcept`, `subject`).
  - Optional fields that may be relevant in your context (e.g., `dosageInstruction`, `dispenseRequest`).

