        self.fhir_client = fhir_client

    def get_medication_data(self, patient_id, resource_type='both'):
        if resource_type == 'both':
            return self._get_combined_medication_data(patient_id)
        elif resource_type in ['MedicationRequest', 'MedicationStatement']:
            return self._get_specific_medication_data(patient_id, resource_type)
        else:
            raise ValueError("Invalid resource type")

    def _get_combined_medication_data(self, patient_id):
        medication_requests = self._fetch_resources('MedicationRequest', patient_id)
        medication_statements = self._fetch_resources('MedicationStatement', patient_id)

        combined_data = []
        for req in medication_requests:
            combined_data.append(MedicationModel.from_fhir(req))

        for stmt in medication_statements:
            combined_data.append(MedicationModel.from_fhir(stmt))

        return combined_data

    def _get_specific_medication_data(self, patient_id, resource_type):
        resources = self._fetch_resources(resource_type, patient_id)
        return [MedicationModel.from_fhir(r) for r in resources]

