        response = requests.get(
            f"{self.fhir_client.base_url}/{resource_type}?patient={patient_id}",
            headers=headers
        )

        if response.status_code == 200:
            return [r for r in response.json()['entry']]
        else:
            raise Exception(f"Failed to retrieve {resource_type} data")

