#### 1. Repository Layer
The repository layer handles the interaction with the FHIR server and returns raw data.

```python
import requests

class BaseRepository:
    def __init__(self, base_url, access_token):
        self.base_url = base_url
        self.access_token = access_token

    def get_resource(self, resource_type, patient_id=None, query_params={}):
        headers = {
            'Authorization': f'Bearer {self.access_token}',
            'Content-Type': 'application/json'
        }

        if patient_id:
            query_params['patient'] = f"Patient/{patient_id}"

        response = requests.get(f"{self.base_url}/{resource_type}", headers=headers, params=query_params)

        if response.status_code == 200:
            return response.json()
        else:
            raise Exception(f"Failed to retrieve {resource_type} data")

class MedicationRepository(BaseRepository):
    def get_medication_requests(self, patient_id):
        query_params = {
            "_count": 100
        }
        return self.get_resource('MedicationRequest', patient_id=patient_id, query_params=query_params)

    def get_medication_statements(self, patient_id):
        query_params = {
            "_count": 100
        }
        return self.get_resource('MedicationStatement', patient_id=patient_id, query_params=query_params)
